export type FiveElement = 'wood' | 'fire' | 'earth' | 'metal' | 'water';
export type Polarity = 'yang' | 'yin';
export type DayBoundaryMode = 'MIDNIGHT_00' | 'ZI_HOUR_23';
/** A single Heavenly Stem (天干) */
export interface StemInfo {
    char: string;
    pinyin: string;
    element: FiveElement;
    polarity: Polarity;
}
/** A single Earthly Branch (地支) */
export interface BranchInfo {
    char: string;
    element: FiveElement;
    hiddenStems: string[];
    mainQi: string;
}
/** One of the Four Pillars (一柱) */
export interface Pillar {
    stem: string;
    branch: string;
    element: FiveElement;
    ganZhi: string;
    stemPolarity: Polarity;
    stemTenGod: string;
    branchElement: FiveElement;
    hiddenStems: HiddenStemInfo[];
    naYin: string;
    xun: string;
    voidBranches: string[];
    growthStage: string;
}
export interface HiddenStemInfo {
    stem: string;
    element: FiveElement;
    polarity: Polarity;
    tenGod: string;
    isMain: boolean;
}
/** The Four Pillars (四柱) */
export interface FourPillars {
    year: Pillar;
    month: Pillar;
    day: Pillar;
    hour: Pillar | null;
}
/** A single 10-year Major Luck Cycle (大运) */
export interface DaYunCycle {
    index: number;
    stem: string;
    branch: string;
    ganZhi: string;
    startYear: number;
    startAge: number;
    endYear: number;
    endAge: number;
    stemTenGod: string;
    branchTenGod: string;
}
/** Da Yun metadata */
export interface DaYunInfo {
    cycles: DaYunCycle[];
    isForward: boolean;
    startYear: number;
    startAge: number;
    startDate: string;
    startOffset: {
        years: number;
        months: number;
        days: number;
        hours: number;
    };
}
export type InteractionType = 'CLASH' | 'COMBINATION_2' | 'TRINE' | 'DIRECTIONAL' | 'PUNISHMENT' | 'DESTRUCTION' | 'HARM';
/** A detected branch interaction */
export interface BranchInteraction {
    type: InteractionType;
    branches: string[];
    pillars: string[];
    resultElement?: FiveElement;
    description: string;
}
export interface SolarTimeInfo {
    trueSolarTime: string;
    trueSolarDateTime: string;
    solarDate: string;
    standardMeridian: number;
    longitudeCorrectionMinutes: number;
    equationOfTimeMinutes: number;
    algorithm: string;
}
export interface CalendarDateTime {
    year: number;
    month: number;
    day: number;
    hour: number | null;
    minute: number | null;
    second: number | null;
}
export interface LunarDateTime extends CalendarDateTime {
    isLeapMonth: boolean;
}
export interface CalendarInfo {
    inputType: 'solar' | 'lunar';
    civilSolar: CalendarDateTime;
    calculationSolar: CalendarDateTime;
    lunar: LunarDateTime;
    zodiac: string;
}
export interface CalculationMetadata {
    trueSolarTimeApplied: boolean;
    dayBoundaryMode: DayBoundaryMode;
    longitude: number | null;
    timezoneBasis: number | string | null;
    dstOffset: number;
}
/** Full output of calculateBaziChart() */
export interface BaziChart {
    pillars: FourPillars;
    dayMaster: StemInfo;
    daYun: DaYunInfo;
    interactions: BranchInteraction[];
    solarTimeInfo: SolarTimeInfo | null;
    calendar: CalendarInfo;
    metadata: CalculationMetadata;
}
export interface BaziInput {
    year: number;
    month: number;
    day: number;
    hour?: number;
    minute?: number;
    longitude?: number;
    timezone?: number;
    timezoneId?: string;
    dstOffset?: number;
    gender: 'male' | 'female';
    calendarType?: 'solar' | 'lunar';
    isLeapMonth?: boolean;
    enableTrueSolarTime?: boolean;
    dayBoundaryMode?: DayBoundaryMode;
}
